import sys
sys.path.insert(0, "../connections") 

import connection_snowflake
import generate_random_user

from snowflake.snowpark.functions import col

#Snowflake Snowpark connection
session = connection_snowflake.new_session

#Create dummy_user_data table, if not exists
session.sql('CREATE TABLE IF NOT EXISTS dummy_user_data ("user_id" NUMBER(38,0) UNIQUE PRIMARY KEY, "first_name" VARCHAR(30), "last_name" VARCHAR(30), "email" VARCHAR(50))').collect()

#Get users data, generated by using randomuser API
#An single API call has maximum of 5000 returned users
#Convert to dataframe & insert into dummy_user_data
persons_data = generate_random_user.generate_random_name_and_surname(5000)
df = session.create_dataframe(persons_data, schema = ["user_id", "first_name", "last_name", "email"])
sorted_df = df.order_by(col("user_id").asc())
sorted_df.write.insert_into("dummy_user_data")
session.table("dummy_user_data").collect()

#Close opened session
session.close()